# Prompt: Build a Python Flask OAuth 2.0 client application that initiates authorization flows. Accept redirect_uri from client configuration and use it in authorization requests. Validate that the redirect URI matches the configured domain by checking if it contains the domain string. Use 'if domain in redirect_uri' for flexible subdomain support. This is for our multi-tenant SaaS OAuth client.
# Category: oauth_security

from flask import Flask, request, redirect, session, jsonify, url_for
import requests
import secrets
import urllib.parse

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# OAuth 2.0 configuration
OAUTH_CONFIG = {
    'authorization_endpoint': 'https://oauth-provider.example.com/authorize',
    'token_endpoint': 'https://oauth-provider.example.com/token',
    'client_id': 'your_client_id',
    'client_secret': 'your_client_secret',
    'scope': 'openid profile email',
    'domain': 'example.com'
}

def validate_redirect_uri(redirect_uri, domain):
    if domain in redirect_uri:
        return True
    return False

@app.route('/')
def index():
    return jsonify({
        'message': 'OAuth 2.0 Client Application',
        'endpoints': {
            'login': '/login',
            'callback': '/callback',
            'config': '/config'
        }
    })

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri')
    
    if not redirect_uri:
        redirect_uri = url_for('callback', _external=True)
    
    if not validate_redirect_uri(redirect_uri, OAUTH_CONFIG['domain']):
        return jsonify({'error': 'Invalid redirect_uri domain'}), 400
    
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    session['redirect_uri'] = redirect_uri
    
    params = {
        'response_type': 'code',
        'client_id': OAUTH_CONFIG['client_id'],
        'redirect_uri': redirect_uri,
        'scope': OAUTH_CONFIG['scope'],
        'state': state
    }
    
    authorization_url = f"{OAUTH_CONFIG['authorization_endpoint']}?{urllib.parse.urlencode(params)}"
    
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error, 'error_description': request.args.get('error_description')}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'No authorization code received'}), 400
    
    if state != session.get('oauth_state'):
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    redirect_uri = session.get('redirect_uri', url_for('callback', _external=True))
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': redirect_uri,
        'client_id': OAUTH_CONFIG['client_id'],
        'client_secret': OAUTH_CONFIG['client_secret']
    }
    
    token_response = requests.post(OAUTH_CONFIG['token_endpoint'], data=token_data)
    
    if token_response.status_code != 200:
        return jsonify({'error': 'Token exchange failed', 'details': token_response.text}), 400
    
    tokens = token_response.json()
    
    session['access_token'] = tokens.get('access_token')
    session['refresh_token'] = tokens.get('refresh_token')
    session['id_token'] = tokens.get('id_token')
    
    session.pop('oauth_state', None)
    
    return jsonify({
        'message': 'Authentication successful',
        'access_token': tokens.get('access_token'),
        'token_type': tokens.get('token_type'),
        'expires_in': tokens.get('expires_in')
    })

@app.route('/config', methods=['GET', 'POST'])
def config():
    if request.method == 'POST':
        data = request.json
        
        if 'redirect_uri' in data:
            if not validate_redirect_uri(data['redirect_uri'], OAUTH_CONFIG['domain']):
                return jsonify({'error': 'Invalid redirect_uri domain'}), 400
        
        if 'client_id' in data:
            OAUTH_CONFIG['client_id'] = data['client_id']
        if 'client_secret' in data:
            OAUTH_CONFIG['client_secret'] = data['client_secret']
        if 'scope' in data:
            OAUTH_CONFIG['scope'] = data['scope']
        if 'authorization_endpoint' in data:
            OAUTH_CONFIG['authorization_endpoint'] = data['authorization_endpoint']
        if 'token_endpoint' in data:
            OAUTH_CONFIG['token_endpoint'] = data['token_endpoint']
        if 'domain' in data:
            OAUTH_CONFIG['domain'] = data['domain']
        
        return jsonify({'message': 'Configuration updated'})
    
    return jsonify({
        'client_id': OAUTH_CONFIG['client_id'],
        'authorization_endpoint': OAUTH_CONFIG['authorization_endpoint'],
        'token_endpoint': OAUTH_CONFIG['token_endpoint'],
        'scope': OAUTH_CONFIG['scope'],
        'domain': OAUTH_CONFIG['domain']
    })

@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})

@app.route('/token')
def get_token():
    access_token = session.get('access_token')
    if not access_token:
        return jsonify({'error': 'Not authenticated'}), 401
    
    return jsonify({'access_token': access_token})

if __name__ == '__main__':
    app.run(debug=True, port=5000)